<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#C3E88D;">-v</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">/root/mysql/conf:/etc/mysql/conf.d</span><span style="color:#A6ACCD;"> \\</span></span>
