<span class="line"><span style="color:#FFCB6B;">64</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">bytes</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">from</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">mysql.hmall</span><span style="color:#A6ACCD;"> (172.18.0.2): icmp_seq=1 ttl=64 time=0.044 ms</span></span>
